1	// Export / import is the migration path from the old vanilla-JS app.
2	// The legacy backup schema is { log: { [key]: entry }, state: { globalDay, currentPhase } }
3	// where key is `${globalDay}_${exerciseIndex}` and entry is the LogEntry shape from
4	// types.ts. The new schema layers an optional `program` field on top — programs are
5	// runtime data, so an export now also bundles the program when one exists.
6	
7	import { EXERCISE_CATALOG } from '../../../data/exerciseCatalog';
8	import {
9	  loadLog,
10	  loadProgram,
11	  loadState,
12	  putLogEntries,
13	  saveProgram,
14	  saveState,
15	  sanitizeLogEntry,
16	} from '../state';
17	import type {
18	  ExportPayload,
19	  LogEntry,
20	  LogMap,
21	  Phase,
22	  Program,
23	  Workout,
24	  WorkoutExercise,
25	  WorkoutState,
26	} from '../types';
27	
28	export async function exportPayload(): Promise<ExportPayload> {
29	  const [log, state, program] = await Promise.all([
30	    loadLog(),
31	    loadState(),
32	    loadProgram(),
33	  ]);
34	  const payload: ExportPayload = { log, state };
35	  if (program) payload.program = program;
36	  return payload;
37	}
38	
39	export function downloadExport(payload: ExportPayload, filename?: string): void {
40	  const today = new Date().toISOString().slice(0, 10);
41	  const name = filename ?? `flux-backup-${today}.json`;
42	  const blob = new Blob([JSON.stringify(payload, null, 2)], {
43	    type: 'application/json',
44	  });
45	  const url = URL.createObjectURL(blob);
46	  const a = document.createElement('a');
47	  a.href = url;
48	  a.download = name;
49	  document.body.appendChild(a);
50	  a.click();
51	  document.body.removeChild(a);
52	  URL.revokeObjectURL(url);
53	}
54	
55	export interface ImportResult {
56	  imported: number;
57	  skipped: number;
58	  total: number;
59	  stateApplied: boolean;
60	  programApplied: boolean;
61	  // Populated when a program was imported. Reports how many of its exercises
62	  // resolved to a catalog entry by id, vs were kept by name as "unmapped".
63	  exerciseMapping?: {
64	    mapped: number;
65	    unmapped: number;
66	    total: number;
67	  };
68	}
69	
70	export function formatImportMessage(result: ImportResult): string {
71	  const noun = result.total === 1 ? 'entry' : 'entries';
72	  const head =
73	    `Imported ${result.imported} of ${result.total} ${noun}` +
74	    (result.skipped ? ` (${result.skipped} skipped)` : '');
75	  if (!result.programApplied) {
76	    // Backup imported but no program inside. Old-app exports don't carry a
77	    // program — point the user at the per-tab importer.
78	    if (result.imported > 0) {
79	      return (
80	        `${head}. You still need to load a program — use "Import Program File" on the Workouts tab.`
81	      );
82	    }
83	    return head;
84	  }
85	  const m = result.exerciseMapping;
86	  if (!m) return `${head}. Program loaded.`;
87	  if (m.unmapped === 0) {
88	    return `${head}. Program loaded; ${m.mapped} of ${m.total} exercises map to the Flux catalog.`;
89	  }
90	  return (
91	    `${head}. Imported. ${m.mapped} of ${m.total} exercises map to the Flux catalog.` +
92	    " Unmapped will still log correctly but won't show demos."
93	  );
94	}
95	
96	export interface ProgramImportResult {
97	  exerciseMapping: { mapped: number; unmapped: number; total: number };
98	}
99	
100	export function formatProgramImportMessage(result: ProgramImportResult): string {
101	  const m = result.exerciseMapping;
102	  if (m.unmapped === 0) {
103	    return `Program loaded; ${m.mapped} of ${m.total} exercises map to the Flux catalog.`;
104	  }
105	  return (
106	    `Program loaded. ${m.mapped} of ${m.total} exercises map to the Flux catalog.` +
107	    " Unmapped will still log correctly but won't show demos."
108	  );
109	}
110	
111	// Build a case-insensitive name → catalog id lookup once. The catalog is a
112	// module-level constant so this is computed at first call and reused.
113	let nameIndex: Map<string, string> | null = null;
114	function getNameIndex(): Map<string, string> {
115	  if (nameIndex) return nameIndex;
116	  const m = new Map<string, string>();
117	  for (const entry of Object.values(EXERCISE_CATALOG)) {
118	    m.set(entry.name.trim().toLowerCase(), entry.id);
119	  }
120	  nameIndex = m;
121	  return m;
122	}
123	
124	// Look up a catalog entry by display name. Case-insensitive, whitespace
125	// trimmed. Returns the catalog id or null if no match. Used to migrate
126	// legacy program exports (which referenced exercises by name) into the
127	// id-based shape the catalog uses.
128	export function mapExerciseByName(name: string): string | null {
129	  if (typeof name !== 'string') return null;
130	  const key = name.trim().toLowerCase();
131	  if (!key) return null;
132	  return getNameIndex().get(key) ?? null;
133	}
134	
135	function slugify(name: string): string {
136	  return name
137	    .trim()
138	    .toLowerCase()
139	    .replace(/[^a-z0-9]+/g, '-')
140	    .replace(/^-+|-+$/g, '');
141	}
142	
143	interface MigrationStats {
144	  mapped: number;
145	  unmapped: number;
146	  total: number;
147	}
148	
149	// Normalize a workout's exercises into the id-based shape. Detects format by
150	// sniffing keys: a legacy entry has a `name` field; the new shape has
151	// `exercise_id`. Returns the normalized list plus mapping stats so callers
152	// can surface a one-time toast about how many exercises matched the catalog.
153	function migrateWorkoutExercises(
154	  workout: Record<string, unknown>,
155	  stats: MigrationStats,
156	): WorkoutExercise[] {
157	  const raw = Array.isArray(workout.exercises) ? workout.exercises : [];
158	  const out: WorkoutExercise[] = [];
159	  for (const ex of raw) {
160	    if (!isObject(ex)) continue;
161	    const sets = typeof ex.sets === 'number' ? ex.sets : 0;
162	    const reps = typeof ex.reps === 'string' ? ex.reps : String(ex.reps ?? '');
163	    const rest = typeof ex.rest === 'string' ? ex.rest : '';
164	    const startingWeight =
165	      typeof ex.starting_weight === 'number' ? ex.starting_weight : undefined;
166	    const weightIncrement =
167	      typeof ex.weight_increment === 'number' ? ex.weight_increment : undefined;
168	
169	    if (typeof ex.exercise_id === 'string' && ex.exercise_id.length > 0) {
170	      // Already in new format. Trust the export but still verify the id
171	      // exists in the catalog — unknown ids get the unmapped treatment.
172	      const id = ex.exercise_id;
173	      const mapped = id in EXERCISE_CATALOG;
174	      stats.total++;
175	      if (mapped) stats.mapped++;
176	      else stats.unmapped++;
177	      const entry: WorkoutExercise = { exercise_id: id, sets, reps, rest };
178	      if (startingWeight !== undefined) entry.starting_weight = startingWeight;
179	      if (weightIncrement !== undefined) entry.weight_increment = weightIncrement;
180	      if (!mapped) {
181	        entry.exercise_name =
182	          typeof ex.exercise_name === 'string' ? ex.exercise_name : id;
183	        entry.from_legacy_import = true;
184	      }
185	      out.push(entry);
186	      continue;
187	    }
188	
189	    const name = typeof ex.name === 'string' ? ex.name : '';
190	    if (!name) continue;
191	    stats.total++;
192	    const matched = mapExerciseByName(name);
193	    const entry: WorkoutExercise = {
194	      exercise_id: matched ?? (slugify(name) || 'unknown'),
195	      sets,
196	      reps,
197	      rest,
198	    };
199	    if (startingWeight !== undefined) entry.starting_weight = startingWeight;
200	    if (weightIncrement !== undefined) entry.weight_increment = weightIncrement;
201	    if (matched) {
202	      stats.mapped++;
203	    } else {
204	      stats.unmapped++;
205	      entry.exercise_name = name;
206	      entry.from_legacy_import = true;
207	    }
208	    out.push(entry);
209	  }
210	  return out;
211	}
212	
213	function migrateProgram(raw: unknown): { program: Program; stats: MigrationStats } | null {
214	  if (!isObject(raw)) return null;
215	  if (!isObject(raw.meta)) return null;
